CREATE OR REPLACE PROCEDURE cargar_staging_votantes(p_path TEXT)
LANGUAGE plpgsql
AS $$
BEGIN
    TRUNCATE staging_votantes;

    EXECUTE format(
        'COPY staging_votantes FROM %L WITH (FORMAT csv, HEADER true, DELIMITER '','', ENCODING ''LATIN1'')',
        p_path
    );
END;
$$;
